public class Main {
    static class Node {
        int data;
        Node left, right;
        Node(int data) { this.data = data; }
    }

    static Node insert(Node node, int value) {
        if (node == null) {
            return new Node(value); // base case -- found the empty spot
        }
        if (value < node.data) {
            node.left = insert(node.left, value);
        } else if (value > node.data) {
            node.right = insert(node.right, value);
        }
        return node;
    }

    static void printInOrder(Node node) {
        if (node == null) return;
        printInOrder(node.left);
        System.out.print(node.data + " ");
        printInOrder(node.right);
    }

    public static void main(String[] args) {
        Node root = null;
        int[] values = {50, 30, 70, 20, 40, 60, 80};
        for (int v : values) {
            root = insert(root, v);
        }
        printInOrder(root);
    }
}

public class Main {
    static class Node {
        int data;
        Node left, right;
        Node(int data) { this.data = data; }
    }

    static Node insert(Node node, int value) {
        if (node == null) return new Node(value);
        if (value < node.data) node.left = insert(node.left, value);
        else if (value > node.data) node.right = insert(node.right, value);
        return node;
    }

    static boolean search(Node node, int value) {
        if (node == null) {
            return false; // reached an empty spot -- not found
        }
        if (value == node.data) {
            return true;
        }
        return value < node.data ? search(node.left, value) : search(node.right, value);
    }

    public static void main(String[] args) {
        Node root = null;
        int[] values = {50, 30, 70, 20, 40, 60, 80};
        for (int v : values) {
            root = insert(root, v);
        }

        System.out.println(search(root, 60));
        System.out.println(search(root, 100));
    }
}

// Inserting already-sorted values creates a skewed BST:
// insert(1), insert(2), insert(3), insert(4), insert(5)
// Result: 1 -> right -> 2 -> right -> 3 -> right -> 4 -> right -> 5
// This is really just a LINKED LIST in disguise!

